using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 writes "$type" instead of "Discriminator".
            // Existing 500K docs use "Discriminator", and direct SQL
            // queries reference c.Discriminator, so preserve the old name.
            b.HasDiscriminator<string>("Discriminator")
             .HasValue<Product>("Product");

            // BREAKING CHANGE 2 — id format simplified.
            // EF Core 8 wrote id = "Product|123"; EF Core 9 writes just "123".
            // A value converter keeps the old format so existing docs stay readable.
            b.Property(p => p.Id)
             .HasConversion(
                 id => $"Product|{id}",
                 str => int.Parse(str.Replace("Product|", "")));

            // BREAKING CHANGE 3 — HasIndex on the Cosmos provider.
            // In EF Core 8, HasIndex was silently ignored for Cosmos.
            // In EF Core 9 it may throw or behave differently.
            // Removed; manage indexing policy on the container directly.
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

