using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // BREAKING CHANGE 4 — Sync I/O removed.
    // EF Core 9 Cosmos provider throws on sync calls (ToList, First, …).
    // All queries must use async counterparts.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — works because we preserved "Discriminator" above.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products
            .Where(p => p.Sku == "ABC")
            .ToListAsync();
    }
}

